-- NULL 데이터로 발생하는 현상
-- NULL은 개수나, 통계에서 계산되지 않는 문제 발생
SELECT sum(SALARY), count(salary), count(*)
	FROM EMPLOYEE;

-- NVL() NULL 여부를 판단, 값이 NULL일 경우 다른 데이터로 반환
SELECT EMP_ID, EMP_NAME, SALARY, DEPT_ID, TO_CHAR(HIRE_DATE, 'YYYY-MM-DD') AS 입사일
	FROM EMPLOYEE
-- WHERE SALARY IS NULL;                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                       